#pragma once

#include <string>
#include <vector>

#include "source/common/common/logger.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Configuration for a header injection rule
 */
struct HeaderInjectionRule {
  std::string header_name;
  std::string header_value;
  bool inject_request{true};
  bool inject_response{false};
};

/**
 * Configuration container for custom header injection filter
 */
class Config : public Logger::Loggable<Logger::Id::config> {
public:
  explicit Config(const std::vector<HeaderInjectionRule>& rules) : rules_(rules) {}

  const std::vector<HeaderInjectionRule>& rules() const { return rules_; }

private:
  const std::vector<HeaderInjectionRule> rules_;
};

using ConfigSharedPtr = std::shared_ptr<Config>;

/**
 * Custom Header Injection filter that injects configurable headers into requests and/or responses
 */
class CustomHeaderInjectionFilter : public Http::StreamFilter,
                                     public Logger::Loggable<Logger::Id::filter> {
public:
  explicit CustomHeaderInjectionFilter(const ConfigSharedPtr config);
  ~CustomHeaderInjectionFilter() override;

  // Http::StreamFilterBase
  void onDestroy() override {}

  // StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;
  Http::FilterDataStatus decodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks&) override {}

  // StreamEncoderFilter
  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
    return Http::Filter1xxHeadersStatus::Continue;
  }
  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;
  Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
    return Http::FilterMetadataStatus::Continue;
  }
  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks&) override {}

private:
  const ConfigSharedPtr config_;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "envoy/http/header_map.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(const ConfigSharedPtr config)
    : config_(config) {}

CustomHeaderInjectionFilter::~CustomHeaderInjectionFilter() = default;

Http::FilterHeadersStatus CustomHeaderInjectionFilter::decodeHeaders(
    Http::RequestHeaderMap& headers, bool) {
  // Inject request headers based on configuration
  for (const auto& rule : config_->rules()) {
    if (rule.inject_request) {
      headers.setCopy(Http::LowerCaseString(rule.header_name), rule.header_value);
    }
  }
  return Http::FilterHeadersStatus::Continue;
}

Http::FilterHeadersStatus CustomHeaderInjectionFilter::encodeHeaders(
    Http::ResponseHeaderMap& headers, bool) {
  // Inject response headers based on configuration
  for (const auto& rule : config_->rules()) {
    if (rule.inject_response) {
      headers.setCopy(Http::LowerCaseString(rule.header_name), rule.header_value);
    }
  }
  return Http::FilterHeadersStatus::Continue;
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#pragma once

#include "envoy/server/filter_config.h"

#include "source/extensions/filters/http/common/factory_base.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Custom configuration for the custom header injection filter factory
 */
struct CustomHeaderInjectionConfig {
  struct HeaderInjectionRule {
    std::string header_name;
    std::string header_value;
    bool inject_request = true;
    bool inject_response = false;
  };
  std::vector<HeaderInjectionRule> rules;
};

/**
 * Config registration for the custom header injection filter.
 */
class CustomHeaderInjectionFilterFactory
    : public Common::FactoryBase<CustomHeaderInjectionConfig> {
public:
  CustomHeaderInjectionFilterFactory()
      : FactoryBase("envoy.filters.http.custom_header_injection") {}

private:
  Http::FilterFactoryCb createFilterFactoryFromProtoTyped(
      const CustomHeaderInjectionConfig& proto_config, const std::string& stats_prefix,
      Server::Configuration::FactoryContext& context) override;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/config.h"

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "envoy/registry/registry.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

Http::FilterFactoryCb CustomHeaderInjectionFilterFactory::createFilterFactoryFromProtoTyped(
    const CustomHeaderInjectionConfig& proto_config, const std::string&,
    Server::Configuration::FactoryContext&) {
  // Convert the protobuf config to filter config
  std::vector<HeaderInjectionRule> rules;
  for (const auto& rule : proto_config.rules) {
    rules.emplace_back(HeaderInjectionRule{
        rule.header_name,
        rule.header_value,
        rule.inject_request,
        rule.inject_response,
    });
  }

  ConfigSharedPtr filter_config(std::make_shared<Config>(rules));

  return [filter_config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    callbacks.addStreamFilter(
        Http::StreamFilterSharedPtr{new CustomHeaderInjectionFilter(filter_config)});
  };
}

/**
 * Static registration for the custom header injection filter.
 */
REGISTER_FACTORY(CustomHeaderInjectionFilterFactory,
                 Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "test/mocks/http/mocks.h"
#include "test/test_common/utility.h"

#include "gtest/gtest.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

class CustomHeaderInjectionFilterTest : public testing::Test {
public:
  void SetUp() override {
    std::vector<HeaderInjectionRule> rules;
    rules.push_back({"x-custom-header", "custom-value", true, false});
    rules.push_back({"x-response-header", "response-value", false, true});
    config_ = std::make_shared<Config>(rules);
    filter_ = std::make_unique<CustomHeaderInjectionFilter>(config_);
  }

  std::shared_ptr<Config> config_;
  std::unique_ptr<CustomHeaderInjectionFilter> filter_;
};

TEST_F(CustomHeaderInjectionFilterTest, InjectsRequestHeaders) {
  Http::TestRequestHeaderMapImpl headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(headers, false));
  EXPECT_EQ("custom-value", headers.get_("x-custom-header"));
}

TEST_F(CustomHeaderInjectionFilterTest, InjectsResponseHeaders) {
  Http::TestResponseHeaderMapImpl headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(headers, false));
  EXPECT_EQ("response-value", headers.get_("x-response-header"));
}

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

